// Extrai dados da mensagem Evolution API
const webhookBody = $('Webhook Evolution API').first().json.body || $('Webhook Evolution API').first().json;
const phone = (webhookBody?.data?.key?.remoteJid || webhookBody?.data?.from || '').replace('@s.whatsapp.net', '').replace(/\D/g, '');
const message = webhookBody?.data?.message?.conversation || webhookBody?.data?.message?.extendedTextMessage?.text || webhookBody?.message || '';
const hasMedia = ['documentMessage', 'imageMessage'].includes(webhookBody?.data?.messageType);

// Dados da sessão do Supabase
const sessaoArr = $input.all();
const sessao = sessaoArr.length > 0 && sessaoArr[0].json?.id ? sessaoArr[0].json : null;
const step = sessao?.step ?? 0;
const dados = sessao?.dados_candidato ? (typeof sessao.dados_candidato === 'string' ? JSON.parse(sessao.dados_candidato) : sessao.dados_candidato) : {};

const SUPABASE_URL = $vars.SUPABASE_URL;
const SUPABASE_KEY = $vars.SUPABASE_KEY;
const GOOGLE_KEY = $vars.GOOGLE_MAPS_API_KEY;
const ENDERECO_SEDE = $vars.ENDERECO_SEDE;
const RAIO_MAX = parseInt($vars.RAIO_MAXIMO_KM || '15');
const ANTHROPIC_KEY = $vars.ANTHROPIC_API_KEY;

async function supabaseRequest(method, path, body) {
  const resp = await fetch(`${SUPABASE_URL}/rest/v1/${path}`, {
    method,
    headers: {
      'apikey': SUPABASE_KEY,
      'Authorization': `Bearer ${SUPABASE_KEY}`,
      'Content-Type': 'application/json',
      'Prefer': 'resolution=merge-duplicates,return=representation'
    },
    body: body ? JSON.stringify(body) : undefined
  });
  return resp.json();
}

let resposta = '';
let nextStep = step;
let novosDados = { ...dados };

// Comando SAIR (LGPD)
if (message.trim().toUpperCase() === 'SAIR') {
  await supabaseRequest('DELETE', `candidatos?whatsapp=eq.${phone}`, null);
  await supabaseRequest('DELETE', `sessoes_whatsapp?phone=eq.${phone}`, null);
  return [{ json: { phone, resposta: '🗑️ Seus dados foram removidos conforme solicitado (LGPD). Obrigado e até logo! 👋', nextStep: -1, novosDados: {} } }];
}

switch(step) {
  case 0:
    resposta = `Olá! 👋 Sou o assistente de seleção de talentos.\n\n_Seus dados serão tratados conforme a LGPD. Digite *SAIR* a qualquer momento para removê-los._\n\nPara iniciar seu cadastro, qual é o seu *CPF*? (usado apenas para evitar duplicatas)`;
    nextStep = 1;
    break;

  case 1: {
    const cpf = message.replace(/\D/g, '');
    if (cpf.length !== 11) {
      resposta = '❌ CPF inválido. Por favor, informe seu CPF com 11 dígitos (apenas números):';
      nextStep = 1;
    } else {
      novosDados.cpf_raw = cpf;
      // Verifica duplicata no Supabase
      const dupCheck = await fetch(`${SUPABASE_URL}/rest/v1/candidatos?cpf_raw=eq.${cpf}&select=id,nome`, {
        headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` }
      });
      const dupData = await dupCheck.json();
      const jaExiste = Array.isArray(dupData) && dupData.length > 0;
      resposta = `✅ ${jaExiste ? 'Identificamos seu cadastro! Vamos atualizar suas informações.' : 'CPF registrado!'}\n\nQual é o seu *nome completo* e o *cargo* que você está buscando?\n_(ex: João Silva | Auxiliar Administrativo)_`;
      if (jaExiste) novosDados.candidato_id = dupData[0].id;
      nextStep = 2;
    }
    break;
  }

  case 2: {
    const parts = message.split('|');
    novosDados.nome = parts[0]?.trim() || message.trim();
    novosDados.cargo_desejado = parts[1]?.trim() || '';
    resposta = `Ótimo, *${novosDados.nome}*! 😊\n\nAgora preciso saber sua localização para verificar a proximidade com o posto de trabalho.\n\nPor favor, informe seu *endereço completo* (Rua, Número, Bairro, Cidade, CEP) 📍`;
    nextStep = 3;
    break;
  }

  case 3: {
    // Geolocalização via Google Maps
    try {
      const geoUrl = `https://maps.googleapis.com/maps/api/geocode/json?address=${encodeURIComponent(message)}&key=${GOOGLE_KEY}&language=pt-BR&region=br`;
      const geoResp = await fetch(geoUrl);
      const geoData = await geoResp.json();
      const geocode = geoData.results?.[0];
      const lat = geocode?.geometry?.location?.lat || 0;
      const lng = geocode?.geometry?.location?.lng || 0;
      const enderecoFormatado = geocode?.formatted_address || message;

      const distUrl = `https://maps.googleapis.com/maps/api/distancematrix/json?origins=${encodeURIComponent(enderecoFormatado)}&destinations=${encodeURIComponent(ENDERECO_SEDE)}&key=${GOOGLE_KEY}&language=pt-BR&mode=driving`;
      const distResp = await fetch(distUrl);
      const distData = await distResp.json();
      const element = distData.rows?.[0]?.elements?.[0];
      const distKm = parseFloat(((element?.distance?.value || 999999) / 1000).toFixed(1));
      const durMin = Math.round((element?.duration?.value || 0) / 60);

      novosDados.endereco = enderecoFormatado;
      novosDados.lat = lat;
      novosDados.lng = lng;
      novosDados.distancia_sede_km = distKm;

      if (distKm > RAIO_MAX) {
        novosDados.status = 'fora_raio';
        resposta = `📍 Localização: *${enderecoFormatado}*\n🏢 Posto de trabalho: ${ENDERECO_SEDE}\n📏 Distância: *${distKm} km* — Raio máximo: ${RAIO_MAX} km\n\nInfelizmente esta vaga exige morar em até ${RAIO_MAX} km do local de trabalho. 😔\n\nManterei seu contato para oportunidades na sua região! 🍀`;
        nextStep = -1;
        await supabaseRequest('POST', 'candidatos', { ...novosDados, whatsapp: phone, fonte: 'whatsapp', updated_at: new Date().toISOString() });
      } else {
        resposta = `✅ *Localização validada!* Você está a *${distKm} km* do posto (~${durMin} min).\n\nQuantos *anos de experiência* você tem na área? Descreva brevemente suas últimas experiências:`;
        nextStep = 4;
      }
    } catch(e) {
      resposta = 'Não consegui validar seu endereço. Por favor, informe novamente (Rua, Número, Bairro, Cidade, CEP):';
      nextStep = 3;
    }
    break;
  }

  case 4:
    novosDados.experiencia_descricao = message;
    novosDados.anos_experiencia = parseInt(message.match(/\d+/)?.[0] || '0');
    resposta = `Registrei! 💼\n\nQual é sua *formação acadêmica*?\n_(ex: Ensino Médio Completo, Técnico em Administração, Superior em Gestão)_`;
    nextStep = 5;
    break;

  case 5:
    novosDados.formacao = message;
    resposta = `📚 Formação registrada!\n\nQual sua *disponibilidade de horário* e *pretensão salarial*?\n_(ex: Manhã e tarde | R$ 2.000 – R$ 2.500)_`;
    nextStep = 6;
    break;

  case 6: {
    const p = message.split('|');
    novosDados.disponibilidade_horario = p[0]?.trim() || message;
    novosDados.pretensao_salarial = p[1]?.trim() || '';
    resposta = `Por fim, você pode enviar seu *currículo em PDF*? 📄\n\nCaso não tenha, não se preocupe — já coletamos suas informações! 😊\n_(Se tiver, envie o arquivo aqui no chat. Se não, responda: sem curriculo)_`;
    nextStep = 7;
    break;
  }

  case 7: {
    // Extração via Claude e cálculo de score
    let curriculoJSON = {};
    try {
      const claudeBody = {
        model: 'claude-haiku-4-5-20251001',
        max_tokens: 1024,
        system: 'Você é especialista em análise de currículos. Extraia dados e retorne SOMENTE JSON válido.',
        messages: [{ role: 'user', content: `Extraia dados do currículo/informações do candidato em JSON: {nome, email, telefone, formacao_nivel, anos_experiencia (número), habilidades_array (lista), idiomas_array, certificacoes_array, resumo_profissional}\n\nInformações disponíveis: ${JSON.stringify(novosDados)}\nMensagem: ${message}` }]
      };
      const claudeResp = await fetch('https://api.anthropic.com/v1/messages', {
        method: 'POST',
        headers: { 'x-api-key': ANTHROPIC_KEY, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' },
        body: JSON.stringify(claudeBody)
      });
      const claudeData = await claudeResp.json();
      const text = claudeData.content?.[0]?.text || '{}';
      curriculoJSON = JSON.parse(text.replace(/```json\n?|```/g, '').trim());
    } catch(e) {}

    // Score
    const distKm = parseFloat(novosDados.distancia_sede_km || 99);
    let scoreGeo = distKm <= 8 ? 100 : distKm <= 10 ? 90 : distKm <= 12 ? 80 : distKm <= 13 ? 70 : distKm <= 14 ? 55 : distKm <= 15 ? 40 : 0;
    const anosExp = parseInt(curriculoJSON.anos_experiencia || novosDados.anos_experiencia || 0);
    const formNivel = (curriculoJSON.formacao_nivel || novosDados.formacao || '').toLowerCase();
    let scoreTec = 50 + (anosExp >= 3 ? 20 : anosExp >= 1 ? 10 : 0) + (formNivel.includes('superior') || formNivel.includes('mba') ? 20 : formNivel.includes('técnico') || formNivel.includes('tecnico') ? 10 : 0);
    scoreTec = Math.min(100, scoreTec);
    const scoreComp = 70;
    const scoreFinal = Math.round(scoreTec * 0.5 + scoreGeo * 0.3 + scoreComp * 0.15);
    const aprovado = scoreFinal >= 60 && scoreGeo > 0;
    const status = aprovado ? 'qualificado' : 'banco_espera';

    const candidatoData = {
      ...novosDados,
      ...(curriculoJSON.nome && { nome: curriculoJSON.nome }),
      ...(curriculoJSON.email && { email: curriculoJSON.email }),
      whatsapp: phone,
      habilidades_array: curriculoJSON.habilidades_array || [],
      idiomas_array: curriculoJSON.idiomas_array || [],
      certificacoes_array: curriculoJSON.certificacoes_array || [],
      score_medio: scoreFinal,
      status,
      fonte: 'whatsapp',
      updated_at: new Date().toISOString()
    };
    await supabaseRequest('POST', 'candidatos', candidatoData);

    const nome = novosDados.nome || 'Candidato';
    resposta = aprovado
      ? `✅ *Cadastro realizado com sucesso, ${nome}!*\n\n📍 Localização validada — ${distKm} km do posto de trabalho.\n🎯 Score de aderência: *${scoreFinal}/100*\n\n📬 Você será notificado quando houver vagas compatíveis. Boa sorte! 🍀`
      : `📋 *Dados registrados, ${nome}!*\n\nSeu perfil foi salvo em nosso banco de talentos (score: ${scoreFinal}/100). Entraremos em contato quando houver vagas compatíveis! 🌟`;
    nextStep = -1;
    break;
  }

  default:
    resposta = 'Obrigado! Seu cadastro já foi finalizado. Se quiser atualizar seus dados, entre em contato conosco. 😊';
    nextStep = -1;
}

return [{ json: { phone, resposta, nextStep, novosDados } }];
